#!/usr/bin/env node
// build-creator-bundle.js — Concatenates creator/ files in dependency order
// Run: node build-creator-bundle.js
// Outputs: creator/bundle.js
//
// After regenerating the bundle, users' browsers will serve the new file on the
// next visit. Bump CREATOR_CACHE_KEY in index.html (e.g. babel_creator_v2) if
// creator-main.js also needs refreshing (forces localStorage cache invalidation).
const fs = require('fs');
const path = require('path');

const ORDER = [
  'context.js',
  'generate.js',
  'canvasRenderer.js',
  'exportPdf.js',
  'useMagicWand.js',
  'useLassoSelect.js',
  'useCreatorState.js',
  'useEditHistory.js',
  'useCanvasInteraction.js',
  'useKeyboardShortcuts.js',
  'useProjectIO.js',
  'usePreview.js',
  'PatternCanvas.js',
  'ToolStrip.js',
  'MagicWandPanel.js',
  'SubstituteFromStashModal.js',
  'Sidebar.js',
  'Toast.js',
  'ContextMenu.js',
  'PatternTab.js',
  'ProjectTab.js',
  'LegendTab.js',
  'ExportTab.js',
];

const parts = ORDER.map(name => {
  const src = fs.readFileSync(path.join('creator', name), 'utf8');
  return `/* ─── ${name} ─── */\n${src}`;
});

const banner = `/* creator/bundle.js — AUTO-GENERATED by build-creator-bundle.js
   Do not edit directly. Edit the source files in creator/ and re-run the build. */\n\n`;

const bundle = banner + parts.join('\n\n');
fs.writeFileSync(path.join('creator', 'bundle.js'), bundle, 'utf8');

const kb = (bundle.length / 1024).toFixed(1);
console.log(`creator/bundle.js written — ${bundle.length} bytes (${kb} KB), ${ORDER.length} files merged`);
